<script>
import {defineAsyncComponent} from "vue";
import {warpnetService} from "@/service/service";
export default {
  name: "Root",
  components: {
    ProgressBar: defineAsyncComponent(() => import('@/components/ProgressBar.vue')),
    LogInComponent: defineAsyncComponent(() => import('@/components/LogInComponent.vue')),
  },
  data() {
    return {
      username: "",
      password: "",
      passwordConfirm: "",
      revealPassword: false,
      isFirstRun: null,
      isLoading: false,
      showModal: "",

      userResponsibility: false,
      futureAds: false,
      localStorageLoss: false,
      signUpError: "",
    };
  },
  computed: {
    isPasswordPairValid() {
      return (
        this.password.length > 0 &&
        this.passwordConfirm.length > 0 &&
        this.password === this.passwordConfirm
      );
    },
  },
  async mounted() {
    try {
      this.isFirstRun = await warpnetService.isFirstRun();
    } catch (err) {
      console.error("failed to determine first-run state:", err);
      this.isFirstRun = false;
    }
    console.log("Is first run:", this.isFirstRun);
  },
  methods: {
    async signMeUp() {
      try {
        this.isLoading = true;
        this.signUpError = "";
        // Capture firstRun BEFORE signInUser: by the time the node has
        // a session, IsFirstRun() flips to false on the next call.
        const wasFirstRun = this.isFirstRun === true;
        await warpnetService.signInUser({
          username: this.username,
          password: this.password,
        });
        if (wasFirstRun) {
          // SideNav picks this up on mount and opens the pairing
          // explainer so a brand-new user gets the QR + visual guide
          // immediately, without having to discover the dropdown.
          // Guarded so privacy modes / disabled storage can't throw
          // and abort the routing to Home — onboarding is a nice-to-have,
          // signup completion is not.
          try {
            if (typeof sessionStorage !== "undefined") {
              sessionStorage.setItem("warpnet:show-pairing-onboarding", "1");
            }
          } catch (e) {
            console.warn("sessionStorage write failed, skipping pairing onboarding:", e);
          }
        }
        this.setStep("");
        this.$router.push({ name: "Home" });
      } catch (error) {
        console.error("error signing up:", error);
        this.signUpError = error?.message || "Sign-up failed. Please try again.";
      } finally {
        this.isLoading = false;
      }
    },
    async setStep(step) {
      this.signUpError = "";
      this.showModal = step || ""
    },
    setSignUpStep(step) {
      switch (step) {
        case "step2":
          if (!this.username) {
            return;
          }
          break;
        case "step4":
          if (!this.isPasswordPairValid) {
            return;
          }
          break;
      }
      this.setStep(step);
    },
    esc() {
      this.setStep("");
      this.isLoading = false;
    },
  },
};
</script>
